#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int N, M;
    cin >> N >> M;
    deque<int> dq;
    for (int i = 1; i <= N; i++) dq.push_back(i);
    long long ops = 0;
    for (int t = 0; t < M; t++) {
        int target;
        cin >> target;
        int idx = -1;
        int sz = dq.size();
        for (int i = 0; i < sz; i++) if (dq[i] == target) { idx = i; break; }
        int leftCnt = idx;
        int rightCnt = sz - idx;
        if (leftCnt <= rightCnt) {
            ops += leftCnt;
            for (int i = 0; i < leftCnt; i++) { dq.push_back(dq.front()); dq.pop_front(); }
        } else {
            ops += rightCnt;
            for (int i = 0; i < rightCnt; i++) { dq.push_front(dq.back()); dq.pop_back(); }
        }
        dq.pop_front();
    }
    cout << ops << "\n";
    return 0;
}
